"use strict";parserFactory.register("alicesw.com",()=>new AliceswParser);class AliceswParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=e.querySelector(".tit a").href,r=(await HttpClient.wrapFetch(t)).responseXML.querySelector(".mulu_list");return util.hyperlinksToChapterList(r)}extractSubject(e){return[...e.querySelectorAll(".novel_info > p:nth-child(2) a"),...e.querySelectorAll(".tags_list a")].map(e=>e.textContent).join(", ")}findContent(e){return e.querySelector(".read-content")}findChapterTitle(e){return e.querySelector(".j_chapterName")}findCoverImageUrl(e){return util.getFirstImgSrc(e,".pic")}extractLanguage(){return"zh-CN"}extractTitleImpl(e){return e.querySelector(".novel_title")}extractAuthor(e){let t=e.querySelector(".novel_info > p:nth-child(1) > a");return t?.textContent??super.extractAuthor(e)}extractDescription(e){return e.querySelector(".jianjie p").textContent.trim()}}